arguments.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model before building so the file exists for the pool
var trainer = new ModelTrainerService(
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<ModelTrainerService>(),
    builder.Environment);
trainer.TrainAndSave();

// Register the trained instance as a singleton so the controller gets the labels
builder.Services.AddSingleton(trainer);

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.GetModelPath());

var app = builder.Build();
app.MapControllers();
app.Run();

